490:     calculateTimesheetTotal: function() {
491:         const empId = document.getElementById('timesheetEmployeeSelect').value;
492:         if (!empId) return;
493:         const emp = this.state.employees.find(e => e.id === empId);
494:         
495:         let total = 0;
496:         document.querySelectorAll('.timesheet-day-input').forEach(input => {
497:             total += parseFloat(input.value) || 0;
498:         });
499: 
500:         document.getElementById('timesheetTotalHrs').textContent = `${total.toFixed(2)} hrs`;
501: 
502:         // Overtime rule: hours exceeding 40 hours per week are calculated at 1.5x
503:         let reg = Math.min(40, total);
504:         let ot = Math.max(0, total - 40);
505: 
506:         document.getElementById('timesheetBreakdownHrs').textContent = `${reg.toFixed(2)}h Reg / ${ot.toFixed(2)}h OT`;
507: 
508:         // Estimate gross
509:         const estGross = (reg * emp.rate) + (ot * emp.rate * 1.5);
510:         document.getElementById('timesheetEstGross').textContent = formatCurrency(estGross);
511:     },
